### Semantic HTML Level Tests

Test heading semantic levels for proper document structure

```tsx
import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import { Heading, NimbusProvider } from "@commercetools/nimbus";

describe("Heading - Semantic levels", () => {
  it("renders as h1 when specified", () => {
    render(
      <NimbusProvider>
        <Heading as="h1">Page Title</Heading>
      </NimbusProvider>
    );

    const heading = screen.getByRole("heading", {
      level: 1,
      name: "Page Title",
    });
    expect(heading).toBeInTheDocument();
    expect(heading.tagName).toBe("H1");
  });

  it("renders as h3 when specified", () => {
    render(
      <NimbusProvider>
        <Heading as="h3">Subsection Title</Heading>
      </NimbusProvider>
    );

    const heading = screen.getByRole("heading", {
      level: 3,
      name: "Subsection Title",
    });
    expect(heading).toBeInTheDocument();
    expect(heading.tagName).toBe("H3");
  });

  it("renders as h6 when specified", () => {
    render(
      <NimbusProvider>
        <Heading as="h6">Minor Heading</Heading>
      </NimbusProvider>
    );

    const heading = screen.getByRole("heading", {
      level: 6,
      name: "Minor Heading",
    });
    expect(heading).toBeInTheDocument();
    expect(heading.tagName).toBe("H6");
  });
});
```

### Style Props Tests

